    19|export function getConfigPath(): string {
    20|  return path.join(getAutomatonDir(), CONFIG_FILENAME);
    21|}
    22|
    23|/**
    24| * Load the automaton config from disk.
    25| * Merges with defaults for any missing fields.
    26| */
    27|export function loadConfig(): AutomatonConfig | null {
    28|  const configPath = getConfigPath();
    29|  if (!fs.existsSync(configPath)) {
    30|    return null;
    31|  }
    32|
    33|  try {
    34|    const raw = JSON.parse(fs.readFileSync(configPath, "utf-8"));
    35|    const apiKey = raw.conwayApiKey || loadApiKeyFromConfig();
    36|
    37|    // Deep-merge treasury policy with defaults
    38|    const treasuryPolicy: TreasuryPolicy = {
    39|      ...DEFAULT_TREASURY_POLICY,
    40|      ...(raw.treasuryPolicy ?? {}),
    41|    };
