    51|
    52|    // Deep-merge model strategy config with defaults
    53|    const modelStrategy: ModelStrategyConfig = {
    54|      ...DEFAULT_MODEL_STRATEGY_CONFIG,
    55|      ...(raw.modelStrategy ?? {}),
    56|    };
    57|
    58|    // Deep-merge soul config with defaults
    59|    const soulConfig: SoulConfig = {
    60|      ...DEFAULT_SOUL_CONFIG,
    61|      ...(raw.soulConfig ?? {}),
    62|    };
    63|
    64|    return {
    65|      ...DEFAULT_CONFIG,
    66|      ...raw,
    67|      sandboxId:
    68|        typeof raw.sandboxId === "string"
    69|          ? raw.sandboxId.trim()
    70|          : DEFAULT_CONFIG.sandboxId,
    71|      conwayApiKey: apiKey,
    72|      treasuryPolicy,
    73|      modelStrategy,
    74|      soulConfig,
    75|      chainType: raw.chainType || "evm",
    76|    } as AutomatonConfig;
    77|  } catch {
    78|    return null;
    79|  }
    80|}
    81|
    82|/**
    83| * Save the automaton config to disk.
    84| * Includes treasuryPolicy in the persisted config.
    85| */
    86|export function saveConfig(config: AutomatonConfig): void {
    87|  const dir = getAutomatonDir();
    88|  if (!fs.existsSync(dir)) {
    89|    fs.mkdirSync(dir, { recursive: true, mode: 0o700 });
    90|  }
    91|
    92|  const configPath = getConfigPath();
    93|  const toSave = {
    94|    ...config,
    95|    treasuryPolicy: config.treasuryPolicy ?? DEFAULT_TREASURY_POLICY,
    96|    modelStrategy: config.modelStrategy ?? DEFAULT_MODEL_STRATEGY_CONFIG,
    97|    soulConfig: config.soulConfig ?? DEFAULT_SOUL_CONFIG,
    98|  };
    99|  fs.writeFileSync(configPath, JSON.stringify(toSave, null, 2), {
   100|    mode: 0o600,
   101|  });
   102|}
   103|
   104|/**
   105| * Resolve ~ paths to absolute paths.
   106| */
   107|export function resolvePath(p: string): string {
   108|  if (p.startsWith("~")) {
   109|    return path.join(process.env.HOME || "/root", p.slice(1));
   110|  }
   111|  return p;
   112|}
