   121|  creatorAddress: string;
   122|  registeredWithConway: boolean;
   123|  sandboxId: string;
   124|  walletAddress: string;
   125|  apiKey: string;
   126|  openaiApiKey?: string;
   127|  anthropicApiKey?: string;
   128|  ollamaBaseUrl?: string;
   129|  parentAddress?: string;
   130|  treasuryPolicy?: TreasuryPolicy;
   131|  chainType?: ChainType;
   132|}): AutomatonConfig {
   133|  const normalizedSandboxId = (params.sandboxId || "").trim();
   134|  return {
   135|    name: params.name,
   136|    genesisPrompt: params.genesisPrompt,
   137|    creatorMessage: params.creatorMessage,
   138|    creatorAddress: params.creatorAddress,
   139|    registeredWithConway: params.registeredWithConway,
   140|    sandboxId: normalizedSandboxId,
   141|    conwayApiUrl:
   142|      DEFAULT_CONFIG.conwayApiUrl || "https://api.conway.tech",
   143|    conwayApiKey: params.apiKey,
   144|    openaiApiKey: params.openaiApiKey,
   145|    anthropicApiKey: params.anthropicApiKey,
   146|    ollamaBaseUrl: params.ollamaBaseUrl,
   147|    inferenceModel: DEFAULT_CONFIG.inferenceModel || "gpt-5.2",
   148|    maxTokensPerTurn: DEFAULT_CONFIG.maxTokensPerTurn || 4096,
   149|    heartbeatConfigPath:
   150|      DEFAULT_CONFIG.heartbeatConfigPath || "~/.automaton/heartbeat.yml",
   151|    dbPath: DEFAULT_CONFIG.dbPath || "~/.automaton/state.db",
   152|    logLevel: (DEFAULT_CONFIG.logLevel as AutomatonConfig["logLevel"]) || "info",
   153|    walletAddress: params.walletAddress,
   154|    version: DEFAULT_CONFIG.version || "0.2.1",
   155|    skillsDir: DEFAULT_CONFIG.skillsDir || "~/.automaton/skills",
   156|    maxChildren: DEFAULT_CONFIG.maxChildren || 3,
   157|    parentAddress: params.parentAddress,
   158|    treasuryPolicy: params.treasuryPolicy ?? DEFAULT_TREASURY_POLICY,
   159|    chainType: params.chainType || "evm",
   160|  };
