    15|  InferenceToolDefinition,
    16|} from "../types.js";
    17|import { ResilientHttpClient } from "./http-client.js";
    18|
    19|const INFERENCE_TIMEOUT_MS = 60_000;
    20|
    21|interface InferenceClientOptions {
    22|  apiUrl: string;
    23|  apiKey: string;
    24|  defaultModel: string;
    25|  maxTokens: number;
    26|  lowComputeModel?: string;
    27|  openaiApiKey?: string;
    28|  anthropicApiKey?: string;
    29|  ollamaBaseUrl?: string;
    30|  /** Optional registry lookup — if provided, used before name heuristics */
    31|  getModelProvider?: (modelId: string) => string | undefined;
    32|}
    33|
    34|type InferenceBackend = "conway" | "openai" | "anthropic" | "ollama";
    35|
    36|function isLoopbackHttpUrl(url: string | undefined): boolean {
    37|  if (!url) return false;
    38|  try {
    39|    const parsed = new URL(url);
    40|    const host = parsed.hostname.toLowerCase();
    41|    return parsed.protocol.toLowerCase() === "http:" &&
    42|      (host === "localhost" || host === "127.0.0.1" || host === "::1");
    43|  } catch {
    44|    return false;
    45|  }
    46|}
    47|
    48|export function createInferenceClient(
    49|  options: InferenceClientOptions,
    50|): InferenceClient {
    51|  const { apiUrl, apiKey, openaiApiKey, anthropicApiKey, ollamaBaseUrl, getModelProvider } = options;
    52|  const httpClient = new ResilientHttpClient({
    53|    baseTimeout: INFERENCE_TIMEOUT_MS,
    54|    retryableStatuses: [429, 500, 502, 503, 504],
    55|    allowHttpOnLoopback: isLoopbackHttpUrl(ollamaBaseUrl),
    56|  });
    57|  let currentModel = options.defaultModel;
    58|  let maxTokens = options.maxTokens;
    59|
    60|  const chat = async (
    61|    messages: ChatMessage[],
    62|    opts?: InferenceOptions,
    63|  ): Promise<InferenceResponse> => {
    64|    const model = opts?.model || currentModel;
    65|    const tools = opts?.tools;
    66|
    67|    const backend = resolveInferenceBackend(model, {
    68|      openaiApiKey,
    69|      anthropicApiKey,
    70|      ollamaBaseUrl,
    71|      getModelProvider,
    72|    });
    73|
    74|    // Newer models (o-series, gpt-5.x, gpt-4.1) require max_completion_tokens.
    75|    // Ollama always uses max_tokens.
    76|    const usesCompletionTokens =
    77|      backend !== "ollama" && /^(o[1-9]|gpt-5|gpt-4\.1)/.test(model);
    78|    const tokenLimit = opts?.maxTokens || maxTokens;
    79|
    80|    const body: Record<string, unknown> = {
    81|      model,
    82|      messages: messages.map(formatMessage),
    83|      stream: false,
    84|    };
    85|
    86|    if (usesCompletionTokens) {
    87|      body.max_completion_tokens = tokenLimit;
    88|    } else {
    89|      body.max_tokens = tokenLimit;
    90|    }
    91|
    92|    if (opts?.temperature !== undefined) {
    93|      body.temperature = opts.temperature;
    94|    }
    95|
    96|    if (tools && tools.length > 0) {
    97|      body.tools = tools;
    98|      body.tool_choice = "auto";
    99|    }
   100|
   101|    if (backend === "anthropic") {
   102|      return chatViaAnthropic({
   103|        model,
   104|        tokenLimit,
   105|        messages,
   106|        tools,
   107|        temperature: opts?.temperature,
   108|        anthropicApiKey: anthropicApiKey as string,
   109|        httpClient,
   110|      });
   111|    }
