   115|      backend === "ollama" ? (ollamaBaseUrl as string).replace(/\/$/, "") :
   116|      apiUrl;
   117|    const openAiLikeApiKey =
   118|      backend === "openai" ? (openaiApiKey as string) :
   119|      backend === "ollama" ? "ollama" :
   120|      apiKey;
   121|
   122|    return chatViaOpenAiCompatible({
