   156|
   157|function formatMessage(
   158|  msg: ChatMessage,
   159|): Record<string, unknown> {
   160|  const formatted: Record<string, unknown> = {
   161|    role: msg.role,
   162|    content: msg.content,
   163|  };
   164|
   165|  if (msg.name) formatted.name = msg.name;
   166|  if (msg.tool_calls) formatted.tool_calls = msg.tool_calls;
