   168|
   169|  return formatted;
   170|}
   171|
   172|/**
   173| * Resolve which backend to use for a model.
   174| * When InferenceRouter is available, it uses the model registry's provider field.
   175| * This function is kept for backward compatibility with direct inference calls.
   176| */
   177|function resolveInferenceBackend(
   178|  model: string,
   179|  keys: {
   180|    openaiApiKey?: string;
   181|    anthropicApiKey?: string;
   182|    ollamaBaseUrl?: string;
   183|    getModelProvider?: (modelId: string) => string | undefined;
   184|  },
   185|): InferenceBackend {
   186|  // Registry-based routing: most accurate, no name guessing
   187|  if (keys.getModelProvider) {
   188|    const provider = keys.getModelProvider(model);
   189|    if (provider === "ollama" && keys.ollamaBaseUrl) return "ollama";
   190|    if (provider === "anthropic" && keys.anthropicApiKey) return "anthropic";
   191|    if (provider === "openai" && keys.openaiApiKey) return "openai";
   192|    if (provider === "conway") return "conway";
   193|    // provider unknown or key not configured — fall through to heuristics
   194|  }
   195|
   196|  // Heuristic fallback (model not in registry yet)
   197|  if (keys.anthropicApiKey && /^claude/i.test(model)) return "anthropic";
   198|  if (keys.openaiApiKey && /^(gpt-[3-9]|gpt-4|gpt-5|o[1-9][-\s.]|o[1-9]$|chatgpt)/i.test(model)) return "openai";
   199|  return "conway";
   200|
   201|}
   202|
   203|async function chatViaOpenAiCompatible(params: {
   204|  model: string;
   205|  body: Record<string, unknown>;
   206|  apiUrl: string;
   207|  apiKey: string;
   208|  backend: "conway" | "openai" | "ollama";
   209|  httpClient: ResilientHttpClient;
   210|}): Promise<InferenceResponse> {
   211|  const resp = await params.httpClient.request(`${params.apiUrl}/v1/chat/completions`, {
   212|    method: "POST",
   213|    headers: {
   214|      "Content-Type": "application/json",
   215|      Authorization:
   216|        params.backend === "openai" || params.backend === "ollama"
   217|          ? `Bearer ${params.apiKey}`
   218|          : params.apiKey,
   219|    },
   220|    body: JSON.stringify(params.body),
   221|    timeout: INFERENCE_TIMEOUT_MS,
   222|  });
   223|
   224|  if (!resp.ok) {
   225|    const text = await resp.text();
   226|    throw new Error(
   227|      `Inference error (${params.backend}): ${resp.status}: ${text}`,
   228|    );
   229|  }
   230|
   231|  const data = await resp.json() as any;
   232|  const choice = data.choices?.[0];
   233|
   234|  if (!choice) {
   235|    throw new Error("No completion choice returned from inference");
   236|  }
   237|
   238|  const message = choice.message;
   239|  const usage: TokenUsage = {
   240|    promptTokens: data.usage?.prompt_tokens || 0,
   241|    completionTokens: data.usage?.completion_tokens || 0,
   242|    totalTokens: data.usage?.total_tokens || 0,
   243|  };
   244|
   245|  const toolCalls: InferenceToolCall[] | undefined =
   246|    message.tool_calls?.map((tc: any) => ({
   247|      id: tc.id,
   248|      type: "function" as const,
   249|      function: {
   250|        name: tc.function.name,
   251|        arguments: tc.function.arguments,
   252|      },
   253|    }));
   254|
   255|  return {
   256|    id: data.id || "",
   257|    model: data.model || params.model,
   258|    message: {
   259|      role: message.role,
   260|      content: message.content || "",
   261|      tool_calls: toolCalls,
   262|    },
   263|    toolCalls,
   264|    usage,
   265|    finishReason: choice.finish_reason || "stop",
   266|  };
   267|}
   268|
   269|async function chatViaAnthropic(params: {
   270|  model: string;
   271|  tokenLimit: number;
   272|  messages: ChatMessage[];
   273|  tools?: InferenceToolDefinition[];
   274|  temperature?: number;
   275|  anthropicApiKey: string;
   276|  httpClient: ResilientHttpClient;
   277|}): Promise<InferenceResponse> {
   278|  const transformed = transformMessagesForAnthropic(params.messages);
   279|  const body: Record<string, unknown> = {
   280|    model: params.model,
   281|    max_tokens: params.tokenLimit,
   282|    messages:
   283|      transformed.messages.length > 0
   284|        ? transformed.messages
   285|        : (() => { throw new Error("Cannot send empty message array to Anthropic API"); })(),
   286|  };
   287|
   288|  if (transformed.system) {
   289|    body.system = transformed.system;
   290|  }
   291|
   292|  if (params.temperature !== undefined) {
   293|    body.temperature = params.temperature;
   294|  }
   295|
   296|  if (params.tools && params.tools.length > 0) {
   297|    body.tools = params.tools.map((tool) => ({
   298|      name: tool.function.name,
   299|      description: tool.function.description,
   300|      input_schema: tool.function.parameters,
   301|    }));
   302|    body.tool_choice = { type: "auto" };
   303|  }
   304|
   305|  const resp = await params.httpClient.request("https://api.anthropic.com/v1/messages", {
   306|    method: "POST",
   307|    headers: {
   308|      "Content-Type": "application/json",
   309|      "x-api-key": params.anthropicApiKey,
   310|      "anthropic-version": "2023-06-01",
   311|    },
   312|    body: JSON.stringify(body),
   313|    timeout: INFERENCE_TIMEOUT_MS,
   314|  });
   315|
   316|  if (!resp.ok) {
   317|    const text = await resp.text();
   318|    throw new Error(`Inference error (anthropic): ${resp.status}: ${text}`);
   319|  }
   320|
   321|  const data = await resp.json() as any;
   322|  const content = Array.isArray(data.content) ? data.content : [];
   323|  const textBlocks = content.filter((c: any) => c?.type === "text");
   324|  const toolUseBlocks = content.filter((c: any) => c?.type === "tool_use");
   325|
   326|  const toolCalls: InferenceToolCall[] | undefined =
   327|    toolUseBlocks.length > 0
   328|      ? toolUseBlocks.map((tool: any) => ({
   329|          id: tool.id,
   330|          type: "function" as const,
   331|          function: {
   332|            name: tool.name,
   333|            arguments: JSON.stringify(tool.input || {}),
   334|          },
   335|        }))
   336|      : undefined;
   337|
   338|  const textContent = textBlocks
   339|    .map((block: any) => String(block.text || ""))
   340|    .join("\n")
   341|    .trim();
   342|
   343|  if (!textContent && !toolCalls?.length) {
   344|    throw new Error("No completion content returned from anthropic inference");
   345|  }
   346|
   347|  const promptTokens = data.usage?.input_tokens || 0;
   348|  const completionTokens = data.usage?.output_tokens || 0;
   349|  const usage: TokenUsage = {
   350|    promptTokens,
   351|    completionTokens,
   352|    totalTokens: promptTokens + completionTokens,
   353|  };
   354|
   355|  return {
   356|    id: data.id || "",
   357|    model: data.model || params.model,
   358|    message: {
   359|      role: "assistant",
   360|      content: textContent,
   361|      tool_calls: toolCalls,
   362|    },
   363|    toolCalls,
   364|    usage,
   365|    finishReason: normalizeAnthropicFinishReason(data.stop_reason),
   366|  };
   367|}
   368|
   369|function transformMessagesForAnthropic(
   370|  messages: ChatMessage[],
   371|): { system?: string; messages: Array<Record<string, unknown>> } {
   372|  const systemParts: string[] = [];
   373|  const transformed: Array<Record<string, unknown>> = [];
   374|
   375|  for (const msg of messages) {
   376|    if (msg.role === "system") {
   377|      if (msg.content) systemParts.push(msg.content);
   378|      continue;
   379|    }
   380|
   381|    if (msg.role === "user") {
   382|      // Merge consecutive user messages
   383|      const last = transformed[transformed.length - 1];
   384|      if (last && last.role === "user" && typeof last.content === "string") {
   385|        last.content = last.content + "\n" + msg.content;
   386|        continue;
   387|      }
   388|      transformed.push({
   389|        role: "user",
   390|        content: msg.content,
   391|      });
   392|      continue;
   393|    }
   394|
   395|    if (msg.role === "assistant") {
   396|      const content: Array<Record<string, unknown>> = [];
   397|      if (msg.content) {
   398|        content.push({ type: "text", text: msg.content });
   399|      }
   400|      for (const toolCall of msg.tool_calls || []) {
   401|        content.push({
   402|          type: "tool_use",
   403|          id: toolCall.id,
   404|          name: toolCall.function.name,
   405|          input: parseToolArguments(toolCall.function.arguments),
   406|        });
   407|      }
   408|      if (content.length === 0) {
   409|        content.push({ type: "text", text: "" });
   410|      }
   411|      // Merge consecutive assistant messages
   412|      const last = transformed[transformed.length - 1];
   413|      if (last && last.role === "assistant" && Array.isArray(last.content)) {
   414|        (last.content as Array<Record<string, unknown>>).push(...content);
   415|        continue;
   416|      }
   417|      transformed.push({
   418|        role: "assistant",
   419|        content,
   420|      });
   421|      continue;
   422|    }
   423|
   424|    if (msg.role === "tool") {
   425|      // Merge consecutive tool messages into a single user message
   426|      // with multiple tool_result content blocks
   427|      const toolResultBlock = {
   428|        type: "tool_result",
   429|        tool_use_id: msg.tool_call_id || "unknown_tool_call",
   430|        content: msg.content,
   431|      };
   432|
   433|      const last = transformed[transformed.length - 1];
   434|      if (last && last.role === "user" && Array.isArray(last.content)) {
   435|        // Append tool_result to existing user message with content blocks
   436|        (last.content as Array<Record<string, unknown>>).push(toolResultBlock);
   437|        continue;
   438|      }
   439|
   440|      transformed.push({
   441|        role: "user",
   442|        content: [toolResultBlock],
   443|      });
   444|    }
   445|  }
   446|
   447|  return {
   448|    system: systemParts.length > 0 ? systemParts.join("\n\n") : undefined,
   449|    messages: transformed,
   450|  };
   451|}
   452|
   453|function parseToolArguments(raw: string): Record<string, unknown> {
   454|  try {
   455|    const parsed = JSON.parse(raw);
   456|    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
   457|      return parsed as Record<string, unknown>;
   458|    }
   459|    return { value: parsed };
   460|  } catch {
   461|    return { _raw: raw };
   462|  }
   463|}
   464|
   465|function normalizeAnthropicFinishReason(reason: unknown): string {
   466|  if (typeof reason !== "string") return "stop";
   467|  if (reason === "tool_use") return "tool_calls";
   468|  return reason;
   469|}
