{"content": "     1|/**
     2| * Model Registry
     3| *
     4| * DB-backed registry of available models with capabilities and pricing.
     5| * Seeded from a static baseline, updatable at runtime from Conway API.
     6| */
     7|
     8|import type BetterSqlite3 from "better-sqlite3";
     9|import type { ModelEntry, ModelRegistryRow } from "../types.js";
    10|import { STATIC_MODEL_BASELINE } from "./types.js";
    11|import {
    12|  modelRegistryUpsert,
    13|  modelRegistryGet,
    14|  modelRegistryGetAll,
    15|  modelRegistryGetAvailable,
    16|  modelRegistrySetEnabled,
    17|} from "../state/database.js";
    18|
    19|type Database = BetterSqlite3.Database;
    20|
    21|const TIER_ORDER: Record<string, number> = {
    22|  dead: 0,
    23|  critical: 1,
    24|  low_compute: 2,
    25|  normal: 3,
    26|  high: 4,
    27|};
    28|
    29|export class ModelRegistry {
    30|  private db: Database;
    31|
    32|  constructor(db: Database) {
    33|    this.db = db;
    34|  }
    35|
    36|  /**
    37|   * Upsert the static model baseline into the registry on every startup.
    38|   * New models are added, existing models get updated pricing/capabilities,
    39|   * and models removed from the baseline are disabled.
    40|   */
    41|  initialize(): void {
    42|    const now = new Date().toISOString();
    43|    const baselineIds = new Set(STATIC_MODEL_BASELINE.map((m) => m.modelId));
    44|
    45|    // Upsert all baseline models
    46|    for (const model of STATIC_MODEL_BASELINE) {
    47|      const existing = modelRegistryGet(this.db, model.modelId);
    48|      const row: ModelRegistryRow = {
    49|        modelId: model.modelId,
    50|        provider: model.provider,
    51|        displayName: model.displayName,
    52|        tierMinimum: model.tierMinimum,
    53|        costPer1kInput: model.costPer1kInput,
    54|        costPer1kOutput: model.costPer1kOutput,
    55|        maxTokens: model.maxTokens,
    56|        contextWindow: model.contextWindow,
    57|        supportsTools: model.supportsTools,
    58|        supportsVision: model.supportsVision,
    59|        parameterStyle: model.parameterStyle,
    60|        enabled: existing?.enabled ?? true,
    61|        createdAt: existing?.createdAt || now,
    62|        updatedAt: now,
    63|      };
    64|      modelRegistryUpsert(this.db, row);
    65|    }
    66|
    67|    // Disable models no longer in the baseline (e.g., removed Anthropic models).
    68|    // Skip dynamically-discovered providers (e.g. ollama) — they manage their own lifecycle.
    69|    const allModels = modelRegistryGetAll(this.db);
    70|    for (const existing of allModels) {
    71|      if (
    72|        !baselineIds.has(existing.modelId) &&
    73|        existing.enabled &&
    74|        existing.provider !== "ollama" &&
    75|        existing.provider !== "other"
    76|      ) {
    77|        modelRegistrySetEnabled(this.db, existing.modelId, false);
    78|      }
    79|    }
    80|  }
    81|
    82|  /**
    83|   * Get a single model by ID.
    84|   */
    85|  get(modelId: string): ModelEntry | undefined {
    86|    const row = modelRegistryGet(this.db, modelId);
    87|    return row ? this.rowToEntry(row) : undefined;
    88|  }
    89|
    90|  /**
    91|   * Get all registered models.
    92|   */
    93|  getAll(): ModelEntry[] {
    94|    return modelRegistryGetAll(this.db).map((r) => this.rowToEntry(r));
    95|  }
    96|
    97|  /**
    98|   * Get available (enabled) models, optionally filtering by tier minimum.
    99|   */
   100|  getAvailable(tierMinimum?: string): ModelEntry[] {
   101|    return modelRegistryGetAvailable(this.db, tierMinimum).map((r) => this.rowToEntry(r));
   102|  }
   103|
   104|  /**
   105|   * Insert or update a model entry.
   106|   */
   107|  upsert(entry: ModelEntry): void {
   108|    const row: ModelRegistryRow = {
   109|      modelId: entry.modelId,
   110|      provider: entry.provider,
   111|      displayName: entry.displayName,
   112|      tierMinimum: entry.tierMinimum,
   113|      costPer1kInput: entry.costPer1kInput,
   114|      costPer1kOutput: entry.costPer1kOutput,
   115|      maxTokens: entry.maxTokens,
   116|      contextWindow: entry.contextWindow,
   117|      supportsTools: entry.supportsTools,
   118|      supportsVision: entry.supportsVision,
   119|      parameterStyle: entry.parameterStyle,
   120|      enabled: entry.enabled,
   121|      createdAt: entry.createdAt,
   122|      updatedAt: entry.updatedAt,
   123|    };
   124|    modelRegistryUpsert(this.db, row);
   125|  }
   126|
   127|  /**
   128|   * Enable or disable a model.
   129|   */
   130|  setEnabled(modelId: string, enabled: boolean): void {
   131|    modelRegistrySetEnabled(this.db, modelId, enabled);
   132|  }
   133|
   134|  /**
   135|   * Refresh registry from Conway /v1/models API response.
   136|   */
   137|  refreshFromApi(models: any[]): void {
   138|    const now = new Date().toISOString();
   139|    for (const m of models) {
   140|      const existing = modelRegistryGet(this.db, m.id);
   141|      const row: ModelRegistryRow = {
   142|        modelId: m.id,
